@dataclass
class LogEntry:
    """日志条目"""
    line_number: int
    timestamp: Optional[float]
    level: str
    content: str
    raw_data: str
    metadata: dict = field(default_factory=dict)

    def __repr__(self):
        # 安全处理 content 为 None 的情况
        safe_content = self.content if self.content else "<empty>"
        safe_content = safe_content[:50] if len(safe_content) > 50 else safe_content
        return f"<LogEntry #{self.line_number} [{self.level}] {safe_content}>"

    def matches_filter(self, level: str = None, keyword: str = None,
                       start_time: float = None, end_time: float = None) -> bool:
        """检查日志条目是否匹配过滤条件"""
        # 级别过滤
        if level and self.level != level:
            # 支持大小写不敏感和部分匹配
            if level.upper() not in self.level.upper():
                return False

        # 关键词过滤
        if keyword and keyword.lower() not in self.content.lower():
            return False

        # 时间范围过滤
        if start_time and self.timestamp and self.timestamp < start_time:
            return False
        if end_time and self.timestamp and self.timestamp > end_time:
            return False

        return True


@dataclass
class ParseResult:
    """解析结果"""
    entries: List[LogEntry]
    bytes_processed: int
    lines_processed: int
    matches: int
    duration_ms: float
    memory_used_bytes: int = 0
    errors: List[str] = field(default_factory=list)


@dataclass
class Window:
    """滑动窗口定义"""
    start_index: int
    end_index: int
    entries: List[LogEntry] = field(default_factory=list)

    @property
    def size(self) -> int:
        """获取窗口大小（条目数量）"""
        return len(self.entries)

    @property
    def byte_size(self) -> int:
        """获取窗口的字节大小"""
        return sum(len(e.raw_data) for e in self.entries)

    @property
    def is_empty(self) -> bool:
        """窗口是否为空"""
        return len(self.entries) == 0

    def get_level_stats(self) -> dict:
        """获取窗口内各日志级别的统计"""
        stats = {}
        for entry in self.entries:
            stats[entry.level] = stats.get(entry.level, 0) + 1
        return stats

    def get_time_range(self) -> tuple:
        """获取窗口内日志的时间范围"""
        timestamps = [e.timestamp for e in self.entries if e.timestamp]
        if not timestamps:
            return (None, None)
        return (min(timestamps), max(timestamps))


# ============================================================
# 环形缓冲区 - 固定内存，支持滑动窗口
# ============================================================

class RingBuffer:
    """
    固定大小的环形缓冲区
    用于存储最近 N 条日志，避免内存溢出
    """

    def __init__(self, max_size: int = 10000):
        self.max_size = max_size
        self._buffer = [None] * max_size
        self._head = 0      # 下一条写入位置
        self._size = 0
        self._lock = threading.RLock()

    def append(self, item: Any) -> Any:
        """
        添加元素到缓冲区
        返回被淘汰的旧元素（如果有）
        """
        evicted = None
        with self._lock:
            if self._size == self.max_size:
                evicted = self._buffer[self._head]

            self._buffer[self._head] = item
            self._head = (self._head + 1) % self.max_size
            self._size = min(self._size + 1, self.max_size)

        return evicted

    def append_batch(self, items: List[Any]) -> List[Any]:
        """批量添加元素，返回被淘汰的元素列表"""
        evicted = []
        for item in items:
            result = self.append(item)
            if result is not None:
                evicted.append(result)
        return evicted

    def get_recent(self, n: int = None) -> List[Any]:
        """
        获取最近的 N 个元素
        """
        with self._lock:
            if n is None:
                n = self._size

            # 边界检查：处理负数
            n = max(0, min(n, self._size))

            if n == 0:
                return []

            # 安全计算起始位置，避免负数
            start = (self._head - n) % self.max_size

            # 防止 % 操作符返回负数（虽然理论上不会发生）
            start = start % self.max_size

            if start + n <= self.max_size:
                return self._buffer[start:start + n]
            else:
                # 跨越边界，分两段获取
                result = self._buffer[start:]
                result.extend(self._buffer[:n - len(result)])
                return result

    def get_all(self) -> List[Any]:
        """获取所有元素"""
        return self.get_recent(self._size)

    def get_range(self, start: int, end: int) -> List[Any]:
        """获取指定范围的元素 [start, end)"""
        with self._lock:
            if start < 0:
                start = 0
            if end > self._size:
                end = self._size
            if start >= end:
                return []

            count = end - start
            # 计算实际起始位置
            offset = (self._head - self._size) % self.max_size
            actual_start = (offset + start) % self.max_size

            if actual_start + count <= self.max_size:
                return self._buffer[actual_start:actual_start + count]
            else:
                result = self._buffer[actual_start:]
                remaining = count - len(result)
                result.extend(self._buffer[:remaining])
                return result

    def clear(self):
        """清空缓冲区"""
        with self._lock:
            self._buffer = [None] * self.max_size
            self._head = 0
            self._size = 0

    def resize(self, new_size: int):
        """调整缓冲区大小"""
        with self._lock:
            if new_size <= 0:
                raise ValueError("缓冲区大小必须大于0")

            old_buffer = self.get_all()
            self._buffer = [None] * new_size
            self._head = 0
            self._size = 0

            # 保留尽可能多的旧数据
            if len(old_buffer) > new_size:
                old_buffer = old_buffer[-new_size:]

            for item in old_buffer:
                self.append(item)

    @property
    def size(self) -> int:
        return self._size

    @property
    def is_full(self) -> bool:
        return self._size == self.max_size

    @property
    def usage_ratio(self) -> float:
        """使用率"""
        return self._size / self.max_size if self.max_size > 0 else 0


