// ==================== 插件状态机（简化版，移除未使用的状态） ====================

enum PluginState {
    UNKNOWN("未知"),
    LOADING("加载中"),
    LOADED("已加载"),
    RESOLVING_DEPENDENCIES("解析依赖"),
    RESOLVED("依赖已解析"),
    ENABLING("启用中"),
    ENABLED("已启用"),
    DISABLING("禁用中"),
    DISABLED("已禁用"),
    UNLOADING("卸载中"),
    UNLOADED("已卸载"),
    ERROR("错误");

    private final String description;

    PluginState(String description) {
        this.description = description;
    }

    public String getDescription() { return description; }

    public boolean canTransitionTo(PluginState newState) {
        return switch (this) {
            case UNKNOWN -> newState == LOADING;
            case LOADING -> newState == LOADED || newState == ERROR || newState == RESOLVING_DEPENDENCIES;
            case RESOLVING_DEPENDENCIES -> newState == RESOLVED || newState == ERROR;
            case RESOLVED, LOADED -> newState == ENABLING || newState == ERROR;
            case ENABLING -> newState == ENABLED || newState == ERROR;
            case ENABLED -> newState == DISABLING;
            case DISABLING -> newState == DISABLED || newState == ERROR;
            case DISABLED -> newState == LOADING || newState == UNLOADING;
            case UNLOADING -> newState == UNLOADED;
            case ERROR -> newState == LOADING; // 允许从错误状态重试
        };
    }
}

