/**
 * 插件运行时上下文
 * 线程安全设计：所有可变集合均使用线程安全实现
 */
class PluginContext {
    private final String pluginId;
    private final Path dataDirectory;
    private final ClassLoader parentClassLoader;
    private final Map<String, Object> sharedServices;
    private final List<Plugin> dependedBy;  // 修复：改为CopyOnWriteArrayList保证线程安全
    private final Map<String, Object> attributes;  // 新增：插件属性存储

    public PluginContext(String pluginId, Path dataDirectory, ClassLoader parentClassLoader) {
        this.pluginId = pluginId;
        this.dataDirectory = dataDirectory;
        this.parentClassLoader = parentClassLoader;
        this.sharedServices = new ConcurrentHashMap<>();
        this.dependedBy = new CopyOnWriteArrayList<>();  // 线程安全列表
        this.attributes = new ConcurrentHashMap<>();
    }

    public String getPluginId() { return pluginId; }
    public Path getDataDirectory() { return dataDirectory; }
    public ClassLoader getParentClassLoader() { return parentClassLoader; }

    public void registerService(String name, Object service) {
        sharedServices.put(name, service);
    }

    @SuppressWarnings("unchecked")
    public <T> T getService(String name) {
        return (T) sharedServices.get(name);
    }

    public void unregisterService(String name) {
        sharedServices.remove(name);
    }

    public void addDependedBy(Plugin plugin) {
        dependedBy.add(plugin);
    }

    public void removeDependedBy(Plugin plugin) {
        dependedBy.remove(plugin);
    }

    public List<Plugin> getDependedBy() {
        return Collections.unmodifiableList(dependedBy);
    }

    public int getDependedByCount() {
        return dependedBy.size();
    }

    public void setAttribute(String key, Object value) {
        attributes.put(key, value);
    }

    @SuppressWarnings("unchecked")
    public <T> T getAttribute(String key) {
        return (T) attributes.get(key);
    }

    public void removeAttribute(String key) {
        attributes.remove(key);
    }

    /**
     * 清理所有资源
     */
    public void cleanup() {
        sharedServices.clear();
        dependedBy.clear();
        attributes.clear();
    }
}

